-- SQL SEED — cancer_types table — Registre Cancer Tlemcen
-- Generated: 2026 — Source: CIM-O-3 IARC + ICD-10 OMS
-- ════════════════════════════════════════════════════════════
CREATE TABLE IF NOT EXISTS cancer_types (
  id                    INT PRIMARY KEY AUTO_INCREMENT,
  nom                   VARCHAR(200) NOT NULL,
  sous_type             VARCHAR(200),
 code_icd10            VARCHAR(10)  NOT NULL,  -- ex: C50.9
 code_topo_icdo3       VARCHAR(10)  NOT NULL,  -- ex: C50.2 (OBLIGATOIRE IARC)
 code_morpho_icdo3     VARCHAR(10)  NOT NULL,  -- ex: M8500/3 (OBLIGATOIRE IARC)
 comportement          VARCHAR(20),            -- /0 bénin /1 incertain /2 in situ /3 malin
 sexe_concerne         VARCHAR(30),
 tranche_age           VARCHAR(30),
 specialiste_principal VARCHAR(150),
 specialistes_rcp      TEXT,
 chirurgien            VARCHAR(150),
 analyses_anapath      TEXT,
 analyses_radio        TEXT,
 analyses_bio          TEXT,
 marqueurs_tumoraux    VARCHAR(200),
 frequence             VARCHAR(100),
 observations          TEXT,
 is_active             BOOLEAN DEFAULT TRUE,
 created_at            TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);
